--required to make constraints deferrable
-- sql must be distributed to plugins on update


--query to generate following sql
--select 'ALTER TABLE SMART.' || t1.tablename || ' ADD CONSTRAINT ' ||  c1.constraintname || ' FOREIGN KEY (' ||  col1.columnname || ') REFERENCES SMART.' || t2.tablename || '(' || col2.columnname || ') '
--|| ' ON DELETE ' || 
--CASE WHEN fk.DELETERULE = 'S' THEN 'RESTRICT' ELSE 'CASCADE' END
--|| ' ON UPDATE ' ||
--CASE WHEN fk.UPDATERULE = 'S' THEN 'RESTRICT' ELSE 'CASCADE' END
--|| ' DEFERRABLE INITIALLY IMMEDIATE '
--from 
--sys.sysconstraints c1,
--sys.sysforeignkeys fk,
--sys.systables t1,
--sys.sysconglomerates g1,
--sys.syscolumns col1,
--sys.syskeys key2,
--sys.sysconglomerates g2,
--sys.syscolumns col2,
--sys.systables t2
--where c1.tableid = t1.tableid
--and c1.constraintid = fk.constraintid
--and g1.conglomerateid = fk.conglomerateid
--and col1.columnnumber = cast(substr( cast(g1.descriptor as varchar(2000)),8,length(cast(g1.descriptor as varchar(2000))) - 8) as integer)
--and col1.referenceid = g1.tableid
--and fk.keyconstraintid = key2.constraintid
--and key2.conglomerateid = g2.conglomerateid
--and g2.tableid = t2.tableid
--and col2.columnnumber = cast(substr( cast(g2.descriptor as varchar(2000)),15,length(cast(g2.descriptor as varchar(2000))) - 15) as integer)
--and col2.referenceid = g2.tableid
--order by t1.tablename

